<template>
	<view>
		<view class="search-box">
			<u-search placeholder="请输入姓名/手机号码/详细地址" v-model="queryForm.keyword" :show-action="false"
				@search="handelSearch" @clear="handelSearch"></u-search>
		</view>
		<scroll-view @touchmove.stop scroll-y class="express-box" :style="{height:scrollHeight+'px'}"
			@scrolltolower="fetchData">
			<view class="wrap">
				<view class="express-list">
					<view class="express-item" v-for="item,index in list" :key="index"
						@click="handelExpressItemClick(item)">
						<view class="left" v-show="deleteMode">
							<view class="radio" :class="{on:checkDelete(item.id)}" @click="handelSelected(item)">
								<u-icon name="checkbox-mark"></u-icon>
							</view>
						</view>
						<view class="right">
							<view class="top">
								<text class="name">{{item.real_name}}</text>
								<text class="mobile">{{item.mobile}}</text>
							</view>
							<view class="middle">{{item.address}}</view>
							<view class="bottom">
								<view class="radio" :class="{on:item.is_default == 1}" v-show="!deleteMode"
									@click="handelSetDefault(item)">
									<u-icon name="checkbox-mark"></u-icon>
									<text>默认收货地址</text>
								</view>
								<view class="buttons">
									<view class="button-item" @click="handelEdit(item)">
										<u-icon name="edit-pen"></u-icon>
										<text>编辑</text>
									</view>
									<view class="button-item" @click="handelDelete(item)">
										<u-icon name="trash"></u-icon>
										<text>删除</text>
									</view>
								</view>
							</view>
						</view>
					</view>
				</view>
				<u-loadmore :status="loading" icon-type="circle" @loadmore="fetchData" />
			</view>
		</scroll-view>
		<view class="footer">
			<view class="wrap">
				<view class="buttons">
					<template v-if="deleteMode">
						<view class="button-item" @click="() => {
							deleteMode = false
						}">完成</view>
						<view class="button-item button-delete" :class="{'button-disabled':!selectedRows.length}"
							@click="handelDelete()">删除</view>
					</template>
					<template v-else>
						<view class="button-item" @click="() => {
							deleteMode = true
						}">管理</view>
						<view class="button-item" @click="() => {
							$util.on('/pages/ucenter_sub/express/add')
						}">新增地址</view>
					</template>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {

		},
		data() {
			return {
				scrollHeight: 0,

				queryForm: {
					keyword: '',
					page: 0,
					limit: 20,
				},
				list: [],
				total: 0,
				loading: 'loadmore',
				activeItem: {},

				deleteMode: false, // 批量删除模式
				selectedRows: [], // 多选项
			};
		},
		computed: {

		},
		watch: {

		},
		onReady() {
			this.$nextTick(() => {
				uni.createSelectorQuery().select(".express-box").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onLoad() {

		},
		onShow() {
			this.reloadData()
		},
		onHide() {
			this.deleteMode = false
			this.selectedRows = []
			let pages = getCurrentPages();
			let currPage = pages[pages.length - 1]
			currPage.isRefresh = true
		},
		methods: {
			handelSearch() {
				this.reloadData()
			},
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				this.queryForm.page = this.queryForm.page + 1
				const {
					list,
					total
				} = await this.$u.api.getMemberAddressList(this.queryForm)
				this.total = total
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.loading = 'loadmore'
				this.queryForm.page = 0
				this.list = []
				this.fetchData()
			},
			handelExpressItemClick(item) {
				this.activeItem = item
			},
			handelEdit({
				id
			}) {
				this.$util.on(`/pages/ucenter_sub/express/add?id=${id}`)
			},
			async handelDelete(row) {
				if (row) {
					await this.$u.api.deleteMemberAddress({
						ids: [row.id]
					})
					this.$util.msg('删除成功')
					this.selectedRows = []
					this.reloadData()
				} else {
					if (!this.selectedRows.length)
						return false
					let ids = this.selectedRows.map(item => item.id)
					await this.$u.api.deleteMemberAddress({
						ids
					})
					this.$util.msg('删除成功')
					this.selectedRows = []
					this.reloadData()
				}
			},
			checkDelete(id) {
				let index = this.selectedRows.findIndex(item => item.id == id)
				return index == -1 ? false : true
			},
			handelSelected(row) {
				let index = this.selectedRows.findIndex(item => item.id == row.id)
				if (index == -1) {
					this.selectedRows.push(row)
				} else {
					this.selectedRows.splice(index, 1)
				}
			},
			async handelSetDefault({
				id
			}) {
				await this.$u.api.setMemberAddressDefault({
					id
				})
				this.$util.msg('设置成功')
				this.reloadData()
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.search-box {
		background-color: #fff;
		padding: 20rpx;
	}

	.express-box {
		.wrap {
			padding: 20rpx;
		}

		.express-list {
			display: flex;
			flex-direction: column;
			gap: 20rpx;

			.express-item {
				display: flex;
				align-items: center;
				gap: 10rpx;

				.left {
					width: 40rpx;

					.radio {
						display: flex;
						align-items: center;

						::v-deep {
							.u-icon__icon {
								font-size: 20rpx !important;
								color: #fff;
								border-radius: 50%;
								padding: 6rpx;
								background-color: #909399;
							}
						}
					}

					.on {
						::v-deep {
							.u-icon__icon {
								background-color: #fa3534;
							}
						}
					}
				}

				.right {
					flex: 1;
					display: flex;
					flex-direction: column;
					gap: 10rpx;
					background-color: #fff;
					padding: 20rpx;
					border-radius: 10rpx;

					.top {
						.name {
							font-size: 110%;
							font-weight: bold;
						}

						.mobile {
							color: #909399;
						}
					}

					.middle {
						border-bottom: 1px solid #c8c9cc;
						word-wrap: break-word;
						color: #909399;
						padding-bottom: 20rpx;
					}

					.bottom {
						display: flex;
						align-items: center;
						color: #909399;

						.radio {
							display: flex;
							align-items: center;

							::v-deep {
								.u-icon__icon {
									font-size: 20rpx !important;
									color: #fff;
									border-radius: 50%;
									padding: 6rpx;
									background-color: #909399;
								}
							}

							&>text {
								margin-left: 10rpx;
							}
						}

						.on {
							::v-deep {
								.u-icon__icon {
									background-color: #fa3534;
								}
							}
						}

						.buttons {
							flex: 1;
							display: flex;
							justify-content: flex-end;
							gap: 20rpx;

							.button-item {
								&>text {
									margin-left: 5rpx;
								}
							}
						}
					}
				}

			}
		}
	}

	.footer {
		position: fixed;
		bottom: 0;
		bottom: constant(safe-area-inset-bottom);
		bottom: env(safe-area-inset-bottom);
		z-index: 11;
		width: 100%;

		.wrap {
			background-color: #fff;
			padding: 20rpx;
			height: 120rpx;

			.buttons {
				display: flex;
				justify-content: center;
				align-items: center;
				height: 100%;
				gap: 20rpx;

				.button-item {
					border-radius: 40rpx;
					text-align: center;
					padding: 18rpx 0;
				}

				.button-item:nth-child(1) {
					border: 1px solid #0e0d0d;
					flex-basis: 40%;
				}

				.button-item:nth-child(2) {
					color: #fff;
					background-color: #fa3534;
					flex-basis: 60%;
				}

				.button-disabled {
					background-color: #C6C6C6 !important;
					color: #fff !important;
				}
			}
		}
	}
</style>